import React from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  href?: string;
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  href, 
  size = 'md',
  isLoading,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-semibold transition-all duration-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-offset-2";

  const variants = {
    primary: "bg-npt-red text-white hover:bg-npt-red-dark shadow-lg hover:shadow-xl hover:-translate-y-0.5",
    secondary: "bg-white text-npt-black border border-npt-black hover:bg-npt-black hover:text-white",
    outline: "border-2 border-white text-white hover:bg-white hover:text-npt-black"
  };

  const sizes = {
    sm: "px-4 py-2 text-sm",
    md: "px-6 py-3 text-base",
    lg: "px-8 py-4 text-lg"
  };

  const classes = `${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`;

  const content = (
    <>
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {children}
    </>
  );

  if (href) {
    return (
      <Link to={href} className={classes}>
        {content}
      </Link>
    );
  }

  return (
    <motion.button 
      whileTap={{ scale: 0.98 }}
      className={classes} 
      disabled={isLoading}
      {...props}
    >
      {content}
    </motion.button>
  );
};

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Dumbbell } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { NAVIGATION } from '../../constants';
import { Button } from '../ui/Button';

export const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsOpen(false);
  }, [location]);

  return (
    <header 
      className={`fixed top-0 w-full z-50 transition-all duration-300 ${
        isScrolled ? 'bg-white/90 backdrop-blur-md shadow-md py-2' : 'bg-transparent py-4'
      }`}
    >
      <div className="container mx-auto px-4 md:px-6">
        <nav className="flex items-center justify-between">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-2 group">
            <div className={`p-2 rounded-lg transition-colors ${isScrolled ? 'bg-npt-red text-white' : 'bg-white text-npt-red'}`}>
              <Dumbbell className="h-6 w-6" />
            </div>
            <div className="flex flex-col">
              <span className={`text-xl font-heading font-bold leading-none ${isScrolled ? 'text-npt-black' : 'text-white'}`}>
                NEW
              </span>
              <span className={`text-xs font-bold tracking-wider ${isScrolled ? 'text-npt-text' : 'text-white/80'}`}>
                PERSONAL TRAINING
              </span>
            </div>
          </Link>

          {/* Desktop Menu */}
          <div className="hidden lg:flex items-center gap-8">
            {NAVIGATION.map((item) => (
              <Link
                key={item.href}
                to={item.href}
                className={`text-sm font-medium transition-colors hover:text-npt-red ${
                  isScrolled ? 'text-npt-black' : 'text-white'
                } ${location.pathname === item.href ? 'text-npt-red font-bold' : ''}`}
              >
                {item.label}
              </Link>
            ))}
            <Button href="/reservar" size="sm" variant={isScrolled ? 'primary' : 'primary'}>
              Reservar Sesión
            </Button>
          </div>

          {/* Mobile Toggle */}
          <button 
            className="lg:hidden p-2 text-npt-red focus:outline-none"
            onClick={() => setIsOpen(!isOpen)}
            aria-label="Menu"
          >
            {isOpen ? <X className="h-8 w-8" /> : <Menu className={`h-8 w-8 ${isScrolled ? 'text-npt-black' : 'text-white'}`} />}
          </button>
        </nav>
      </div>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: '100vh' }}
            exit={{ opacity: 0, height: 0 }}
            className="fixed inset-0 bg-white z-40 lg:hidden overflow-hidden pt-24 px-4"
          >
            <div className="flex flex-col gap-6 items-center text-center">
              {NAVIGATION.map((item) => (
                <Link
                  key={item.href}
                  to={item.href}
                  className="text-2xl font-heading font-bold text-npt-black hover:text-npt-red transition-colors"
                >
                  {item.label}
                </Link>
              ))}
              <div className="mt-8 w-full max-w-xs">
                <Button href="/reservar" className="w-full justify-center">
                  Reservar Sesión
                </Button>
              </div>

              <div className="mt-auto mb-12 text-npt-text text-sm">
                <p>Medellín, Colombia</p>
                <p>+57 300 597 4290</p>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
};

